var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"정말 이 근처가 맞나요?","JPN":"本当にこの近くなのですか？","ENG":"Are you sure it's around here?","TWN":"真的在這附近嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"다리 뒤로 반쯤 무너진 건물 보이지? 바로 저기야.","JPN":"橋の向こうに半分崩れた建物が見えるでしょ？　そこだよ。","ENG":"See the half-collapsed building behind the bridge? That's it.","TWN":"有看到橋後面倒塌的建築物嗎？就是那個。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"일단 여기서부터 화려하게 화력난사를......!","JPN":"とりあえず、ここからド派手に火力乱射を……！","ENG":"I'll pour them a rain of fire from here first, then...","TWN":"總之先從這裡來個華麗的火力掃射……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 쇳덩어리 좀 치워요! 가급적 평화적으로 해결한다고 했잖아요!","JPN":"その鉄の塊はしまってください！　できるだけ平和に解決すると言ったはずですわ！","ENG":"Will you put that bulky thing away? I said we're going to handle this as peacefully as possible.","TWN":"把那個鐵塊拿開！不是說了要盡可能地和平解決嗎！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"히잉~ 그런 건 재미없는데.","JPN":"え～っ、それじゃ面白くないのに。","ENG":"Boohoo! But that's no fun at all!","TWN":"嗚嗚～那樣很無聊了耶。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"일단 대화부터 해 볼 테니까 다들 따라오세요.","JPN":"まずは話し合いをしてみますので、ついて来てください。","ENG":"I'll try to reason with them first. You just follow me.","TWN":"總之我們先試著跟他們談談，大家跟我來。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"너무 어두운데요?","JPN":"すごく暗いですわね。","ENG":"It's too dark here.","TWN":"這也太暗了吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설마 우리가 너무 늦어서 모두 떠나 버린 거 아닐까요?","JPN":"まさか、来るのが遅すぎてどこかへ行ってしまったかしら？","ENG":"Perhaps we came too late and they've all left.","TWN":"該不會是我們來太晚了，他們已經離開了吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"글쎄? 그런 것 치곤 냄새가 좀 이상한데......","JPN":"どうかな？　その割には嫌な匂いがするけど……","ENG":"I don’t know. This weird smell says differently.","TWN":"誰知道呢？但先不管這些，總覺得這裡的氣味有點奇怪……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"제게 랜턴이 있어요. 켜볼게요.","JPN":"ランタンがあるので、点けてみますね。","ENG":"Here is a lantern. Let's turn it on.","TWN":"我帶了提燈，打開來看看。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐, 뭐야 저건......? 시체......?","JPN":"あ、あれは……？　死体……？","ENG":"W-what are those? Corpses?","TWN":"這、這是什麼……？屍體……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고...... 시체에서 뭔가 자라나고 있어?","JPN":"そして……死体から何かが生えている？","ENG":"And there's something growing on them!","TWN":"而且……屍體上好像還長了什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"레지나 말대로 늦어버렸네. 조금 다른 의미긴 하지만.","JPN":"レジーナの言う通り、着くのが遅かったみたいだね。ちょっと別の意味でだけど。","ENG":"We were too late indeed, but in a very different sense.","TWN":"就如蕾佳娜大人所說，我們來晚了，不過意思稍微不太一樣。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"무슨 한가한 소리에요?!","JPN":"何をのんきなことを言ってるのですか！？","ENG":"What are you murmuring about?","TWN":"妳在說什麼風涼話啊？！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저건 분명 침식체일 거에요! 당장 여기서 나가야......","JPN":"あれはきっと侵食体です！　すぐにここから出ないと……","ENG":"They must be Corrupted Objects! We have to get out of he—","TWN":"那明明是侵蝕體吧！我們得立刻從這裡離開……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......에델?","JPN":"……エデル？","ENG":"Edel?","TWN":"……艾瑟兒？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"성찬의 재료들이 이런 곳에 있었군요.","JPN":"聖餐の材料はこんなところにあったんですね。","ENG":"What a surprise. Ingredients of the feast in a place like this.","TWN":"盛宴的材料在這種地方啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"신선한 풍미가 느껴져요. 아마도 감동적인 만찬이 될 것 같네요.","JPN":"新鮮な香りを感じます。きっと、感動的な晩餐になりますよ。","ENG":"And they feel fresh. This will be a very satisfying meal.","TWN":"能感受到新鮮的風味。應該會是一頓令人感動的晚餐吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐 하고 있어요, 에델?!","JPN":"エデル、何をしているのですの！？","ENG":"What are you doing, Edel?","TWN":"妳在做什麼，艾瑟兒？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"가까이 가면 위험해요! 당장 물러서요!","JPN":"近付くのは危険ですわ！　退がってください！","ENG":"They'll hurt you if you get too close! Get back, now!","TWN":"靠近會很危險的！馬上退後！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"어머나, 레지나 님. 공들여 차린 지식의 성찬이잖아요.","JPN":"あら、レジーナ様。せっかくの知識の聖餐なのですよ？","ENG":"Why, Miss Regina, They must have worked hard to prepare this feast of knowledge for us.","TWN":"哎呀，蕾佳娜大人，這是為我們精心準備的知識盛宴啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"모른 체 하는 건...... 예의에 어긋나지 않을까요?","JPN":"見て見ぬふりをするのは……礼儀に反すると思いませんか？","ENG":"Wouldn't it be rude if we just walked away?","TWN":"如果裝作不知道的話……會違反禮儀吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에...... 에델......","JPN":"エ……エデル……","ENG":"E- Edel!","TWN":"艾……艾瑟兒……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다, 당신...... 그림자에서 뭔가가......","JPN":"あ、あなた……影から何かが……","ENG":"Your shadow... There's something moving in your shadow!","TWN":"妳、妳的……影子裡有什麼……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"아, 이 아이들이요?","JPN":"ああ、この子たちですか？","ENG":"Ah, you mean these babies?","TWN":"啊，您是說這些孩子們嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"후훗, 계속 배가 고프다고 칭얼거리더니 결국 허락도 없이 기어나오네요.","JPN":"ふふっ。お腹が空きすぎて、勝手に出てきてしまったみたいですね。","ENG":"Fu fu, it seems they were too hungry to wait for my permission.","TWN":"呵呵，它們一直吵著說肚子餓，結果不經允許就這麼爬出來了呢。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아이들......?","JPN":"この子たち……？","ENG":"Babies?","TWN":"孩子們……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설마, 그럼 서재에서도......","JPN":"じゃあ、まさか書斎でも……","ENG":"No, was it them back at the library?","TWN":"該不會，在書房也是……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맞아요. 애교도 잘 부리고 말랑말랑해서 굉장히 깜찍한 아이들이랍니다.","JPN":"ええ。愛嬌もあるし、ふわふわしていて、とてもかわいい子たちなんですよ。","ENG":"Correct. They're my cuties, obedient in character and smooth and soft to the touch.","TWN":"沒錯。就是很愛撒嬌，又軟綿綿的可愛孩子喔。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"평소에는 낯가림이 심해서 배고플 때 말고는 나다니질 않거든요.","JPN":"普段は人見知りをして、お腹が空いている時しか出てこないんです。","ENG":"They're shy, so they rarely show themselves unless they're hungry.","TWN":"它們平時怕生得很，除了肚子餓的時候，一般是不會出來的。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그런데 오늘은 왠일인지 무척 활기차더라고요. 상성이 잘 맞나 봐요.","JPN":"でも、今日はなぜかとても元気なんですよ。きっと相性が良いのでしょう。","ENG":"But for some reason, they've been very cheerful today. Maybe they like being around you.","TWN":"但今天不知為什麼特別有精神呢，看來與蕾佳娜大人很合得來啊。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"기회가 되면 다음에 정식으로 소개해 드릴게요. 무척 좋아하시게 될 거에요.","JPN":"機会があったら今度改めて紹介しますね。きっと喜んでいただけると思います。","ENG":"I'll properly introduce you to them later. I'm sure you'll like them very much.","TWN":"下次有機會的話，我們會向您正式介紹它們的，我們想您一定會非常喜歡。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신...... 당신은 대체 뭐죠......?","JPN":"あなた……あなたはいったい……？","ENG":"What... What are you?","TWN":"妳……妳到底是什麼……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"쉿.","JPN":"しっ。","ENG":"Shh.","TWN":"噓。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L1_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"말씀을 아끼세요. 레지나 님.","JPN":"レジーナ様、お静かに。","ENG":"No more talking, Miss Regina.","TWN":"請不要說話，蕾佳娜大人。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"식사 시간이랍니다.","JPN":"今はお食事の時間ですよ。","ENG":"It's time to eat.","TWN":"現在是用餐時間。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};